import { z } from "zod";

export const redactRequestSchema = z.object({
  text: z.string().min(1).max(50000),
  entities: z
    .array(
      z.enum([
        "email",
        "phone",
        "ssn",
        "credit_card",
        "name",
        "address",
        "ip_address",
        "date_of_birth",
      ])
    )
    .optional(),
});

export const redactedEntitySchema = z.object({
  type: z.string(),
  original: z.string(),
  start: z.number(),
  end: z.number(),
});

export const redactResponseSchema = z.object({
  redacted: z.string(),
  entities: z.array(redactedEntitySchema),
  entityCount: z.number(),
});

export type RedactRequest = z.infer<typeof redactRequestSchema>;
export type RedactResponse = z.infer<typeof redactResponseSchema>;
export type RedactedEntity = z.infer<typeof redactedEntitySchema>;
